  -- Block 4b: Guards -- rollback on mismatch or orphan
  DO $$
  DECLARE
    n2015  integer;
    n2016  integer;
    n_null integer;
  BEGIN
    SELECT COUNT(*) INTO n2015  FROM questions
    WHERE  source='pyq' AND language='en' AND centre_id IS NULL AND year=2015;

    SELECT COUNT(*) INTO n2016  FROM questions
    WHERE  source='pyq' AND language='en' AND centre_id IS NULL AND year=2016;

    SELECT COUNT(*) INTO n_null FROM questions
    WHERE  source='pyq' AND language='en' AND centre_id IS NULL AND year IS NULL;

    IF n_null > 0 THEN
      RAISE EXCEPTION
        'ORPHAN CHECK FAILED: % en/pyq rows have year IS NULL. '
        'Rolled back. Inspect: SELECT id,body FROM questions '
        'WHERE source=''pyq'' AND language=''en'' '
        'AND centre_id IS NULL AND year IS NULL;',
        n_null;
    END IF;

    IF n2015 <> 161 OR n2016 <> 168 THEN
      RAISE EXCEPTION
        'BACKFILL MISMATCH: 2015=% (expected 161), 2016=% (expected 168). Rolled back.',
        n2015, n2016;
    END IF;

    RAISE NOTICE 'Guards passed -- 2015=%, 2016=%, NULL=% -- committing.',
      n2015, n2016, n_null;
  END $$;

COMMIT;


-- BLOCK 5: Post-commit verify

SELECT year, COUNT(*) AS n
FROM   questions
WHERE  source='pyq' AND language='en' AND centre_id IS NULL
GROUP  BY year
ORDER  BY year NULLS LAST;
-- EXPECTED: year=2015 n=161 / year=2016 n=168 / no NULL row
